import { getAxisDomainLimit } from "./getAxisDomainLimit.js";
import { getTickNumber } from "../../../ticks.js";
function niceDomain(scaleType, domain, tickNumber) {
  return getScale(scaleType ?? 'linear', domain, [0, 1]).nice(tickNumber).domain();
